import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Login.css";

function Login() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    setError("");

    if (!username || !password) {
      setError("Username dan password harus diisi!");
      return;
    }

    if (password === "12345") {
      navigate("/dashboard");
    } else {
      setError("Password salah! Password yang benar adalah 12345");
      setPassword("");
    }
  };

  return (
    <div className="login-wrapper">
      {/* BACKGROUND DECORATION */}
      <div className="login-background">
        <span className="circle circle-1"></span>
        <span className="circle circle-2"></span>
        <span className="circle circle-3"></span>
      </div>

      <div className="login-container">
        {/* LOGIN CARD */}
        <div className="login-card">
          <header className="login-header">
            <div className="logo">📚</div>
            <h1>Toko Buku Digital</h1>
            <p>Masuk untuk melanjutkan</p>
          </header>

          <form className="login-form" onSubmit={handleLogin} noValidate>
            {/* USERNAME */}
            <div className="form-group">
              <label htmlFor="username">👤 Username</label>
              <input
                id="username"
                type="text"
                placeholder="Masukkan username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className={error ? "input-error" : ""}
                autoComplete="username"
              />
            </div>

            {/* PASSWORD */}
            <div className="form-group">
              <label htmlFor="password">🔒 Password</label>
              <div className="password-wrapper">
                <input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  placeholder="Masukkan password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={error ? "input-error" : ""}
                  autoComplete="current-password"
                />
                <button
                  type="button"
                  className="toggle-password"
                  aria-label="Toggle password visibility"
                  onClick={() => setShowPassword(!showPassword)}
                >
                  {showPassword ? "🙈" : "👁️"}
                </button>
              </div>
            </div>

            {/* ERROR */}
            {error && (
              <div className="error-message" role="alert">
                ⚠️ {error}
              </div>
            )}

            {/* BUTTON */}
            <button type="submit" className="login-btn">
              ✨ Masuk Sekarang
            </button>
          </form>
        </div>

        {/* INFO SECTION */}
        <aside className="login-info">
          <div className="info-card">
            <span className="icon">📖</span>
            <h3>Koleksi Lengkap</h3>
            <p>Ribuan buku digital berkualitas</p>
          </div>

          <div className="info-card">
            <span className="icon">💻</span>
            <h3>Akses Fleksibel</h3>
            <p>Baca di semua perangkat</p>
          </div>

          <div className="info-card">
            <span className="icon">🎓</span>
            <h3>Belajar Efektif</h3>
            <p>Dukung aktivitas belajar Anda</p>
          </div>
        </aside>
      </div>
    </div>
  );
}

export default Login;
